import React from "react";
import { BulletContainer, Container } from "./styles";
import ColorBullet from "./ColorBullet";
import useSettings from "../../storage/useSettings";
import { Box } from "@mui/material";

type ColorBulletsProps = {
	selectedColorId: number | undefined;
	onSelectColor: (colorId: number) => void;
};

const ColorBullets = ({
	selectedColorId,
	onSelectColor,
}: ColorBulletsProps) => {
	const { colors } = useSettings();
	return (
		<Container>
			{colors.map((color) => (
				<BulletContainer
					key={color.id}
					selected={color.id === selectedColorId}
					onClick={() => onSelectColor(color.id)}
				>
					<ColorBullet key={color.id} color={color} />
				</BulletContainer>
			))}
		</Container>
	);
};

export default ColorBullets;
